FROM jsonb_to_recordset('[{"id": "cap-108-chinese-001", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "「『饕餮』是一種古代怪獸，在生物圖鑑與動物園裡找不到，牠和蛟龍、鳳凰\n一樣，都是虛構的動物，□存在文化裡，□□活靈活現，□□有鮮明的圖樣\n形象，□繁殖出豐富的語意象徵。」根據文意脈絡，空格處依序填入下列何\n者最恰當？", "options": ["雖／竟然／除了／卻", "但／可是／僅僅／也", "乃／尚且／居然／與", "只／但卻／不只／還"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 1, "raw_text": "1.   「『饕餮』是一種古代怪獸，在生物圖鑑與動物園裡找不到，牠和蛟龍、鳳凰\n     一樣，都是虛構的動物，□存在文化裡，□□活靈活現，□□有鮮明的圖樣\n     形象，□繁殖出豐富的語意象徵。」根據文意脈絡，空格處依序填入下列何\n     者最恰當？\n     (A)雖／竟然／除了／卻    (B)但／可是／僅僅／也\n     (C)乃／尚且／居然／與    (D)只／但卻／不只／還\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-002", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "英國詩人赫巴德說：「彼此無所求的朋友，才可能是真正的朋友。」這句話\n的涵義與下列何者最接近？", "options": ["交往若帶有目的，就不是真正的友誼", "在朋友困難時伸出援手，才能得到回報", "想獲得朋友，須自己先成為值得結交的人", "人生有許多事不能獨自完成，可知友誼的重要"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 2, "raw_text": "2.   英國詩人赫巴德說：「彼此無所求的朋友，才可能是真正的朋友。」這句話\n     的涵義與下列何者最接近？\n     (A)交往若帶有目的，就不是真正的友誼\n     (B)在朋友困難時伸出援手，才能得到回報\n     (C)想獲得朋友，須自己先成為值得結交的人\n     (D)人生有許多事不能獨自完成，可知友誼的重要\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-003", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "一則符合報導原則的新聞，應避免記者個人主觀的推論與判斷。下列選項何者符\n合上述的報導原則？", "options": ["某卡通玩偶流行全臺，可見民眾都具有赤子之心", "所有砂石車司機都是惡意的肇事者，政府應嚴加取締", "某民代選前造勢晚會，聚集數萬群眾，聲勢浩大，勝券在握", "醫生提出警告，這一波腸病毒可能導致孩童死亡，民眾須有所防範"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 3, "raw_text": "3.   一則符合報導原則的新聞，應避免記者個人主觀的推論與判斷。下列選項何者符\n     合上述的報導原則？\n     (A)某卡通玩偶流行全臺，可見民眾都具有赤子之心\n     (B)所有砂石車司機都是惡意的肇事者，政府應嚴加取締\n     (C)某民代選前造勢晚會，聚集數萬群眾，聲勢浩大，勝券在握\n     (D)醫生提出警告，這一波腸病毒可能導致孩童死亡，民眾須有所防範\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-004", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "「常常我們只記得結果的不完美，卻忘記收穫滿滿的過程。就像吹泡泡，其實不\n需要太在意泡泡不免會破掉。」這句話的涵義與下列何者最接近？", "options": ["真正完美的結果是不可期待的", "無論過程或結果都應力求圓滿", "過程中的收穫比結果是否完美重要", "收穫滿滿的過程有助於結果的完美"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 4, "raw_text": "4.   「常常我們只記得結果的不完美，卻忘記收穫滿滿的過程。就像吹泡泡，其實不\n     需要太在意泡泡不免會破掉。」這句話的涵義與下列何者最接近？\n     (A)真正完美的結果是不可期待的\n     (B)無論過程或結果都應力求圓滿\n     (C)過程中的收穫比結果是否完美重要\n     (D)收穫滿滿的過程有助於結果的完美\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-005", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "兩軍交戰時，有一種策略是「先轉移敵人目標，使他們疏於防範，然後乘其不意，\n攻其不備，取得勝利」。這種策略最適合用下列哪一個成語來形容？", "options": ["拋磚引玉", "裡應外合", "趁火打劫", "聲東擊西"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 5, "raw_text": "5.   兩軍交戰時，有一種策略是「先轉移敵人目標，使他們疏於防範，然後乘其不意，\n     攻其不備，取得勝利」。這種策略最適合用下列哪一個成語來形容？\n     (A)拋磚引玉          (B)裡應外合\n     (C)趁火打劫          (D)聲東擊西\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-006", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "「漢朝刺史巡視的要點有六：一看地方豪強是否恃強凌弱，二看郡守、公侯是否\n損公肥私，三看高官辦案是否草菅人命，四看官員是否任人唯親，五看高官子\n弟是否仗勢欺人，六看官員是否勾結地方豪強、牟取不法利益。」根據這段文\n字，漢朝刺史的職責最可能是下列何者？", "options": ["訪察並薦舉優秀人才", "宣揚朝廷政策與命令", "反映地方民情與百姓需求", "督察各級高官與地方豪強"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 6, "raw_text": "6.   「漢朝刺史巡視的要點有六：一看地方豪強是否恃強凌弱，二看郡守、公侯是否\n     損公肥私，三看高官辦案是否草菅人命，四看官員是否任人唯親，五看高官子\n     弟是否仗勢欺人，六看官員是否勾結地方豪強、牟取不法利益。」根據這段文\n     字，漢朝刺史的職責最可能是下列何者？\n     (A)訪察並薦舉優秀人才     (B)宣揚朝廷政策與命令\n     (C)反映地方民情與百姓需求   (D)督察各級高官與地方豪強\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-007", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "下列詞語「」中的字，何者讀音正確？", "options": ["春寒料「峭」：ㄑㄧㄠˋ", "「湛」藍天空：ㄔㄣˊ", "一掃陰「霾」：ㄌㄧˊ", "胼手「胝」足：ㄉㄧˇ"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 7, "raw_text": "7.   下列詞語「」中的字，何者讀音正確？\n     (A)春寒料「峭」：ㄑㄧㄠˋ  (B)「湛」藍天空：ㄔㄣˊ\n     (C)一掃陰「霾」：ㄌㄧˊ   (D)胼手「胝」足：ㄉㄧˇ\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-008", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "「暇時引讀瑤篇，座前見水華木翠。夜裡趣摘章句，紙上有月白風清。」這段文\n字主要在描寫下列何種意趣？", "options": ["跋涉山水，遍覽自然風光", "閒暇遊逛園林，聆賞天籟之趣", "開卷吟誦，書中自有雋雅美景", "揮毫點染，筆下有無限清風明月"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 8, "raw_text": "8.   「暇時引讀瑤篇，座前見水華木翠。夜裡趣摘章句，紙上有月白風清。」這段文\n     字主要在描寫下列何種意趣？\n     (A)跋涉山水，遍覽自然風光\n     (B)閒暇遊逛園林，聆賞天籟之趣\n     (C)開卷吟誦，書中自有雋雅美景\n     (D)揮毫點染，筆下有無限清風明月\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-009", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "下列文句的標點符號，何者使用最恰當？", "options": ["小弟弟聰明伶俐，富有好奇心，什麼事都非要打破沙鍋問到底不可？", "我不是跟你說過嗎？要得到好成績，不用功是不行的。為何你總是置若罔聞？", "對於這項工作，一來，我沒有這份才能、再來，也沒有時間，只好敬謝不敏了。", "文明的現代：戰爭仍然層出不窮，不禁令人懷疑――歷史是前進的，抑或倒 退的。"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 9, "raw_text": "9.   下列文句的標點符號，何者使用最恰當？\n     (A)小弟弟聰明伶俐，富有好奇心，什麼事都非要打破沙鍋問到底不可？\n     (B)我不是跟你說過嗎？要得到好成績，不用功是不行的。為何你總是置若罔聞？\n     (C)對於這項工作，一來，我沒有這份才能、再來，也沒有時間，只好敬謝不敏了。\n     (D)文明的現代：戰爭仍然層出不窮，不禁令人懷疑――歷史是前進的，抑或倒\n        退的。\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-010", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "下列文句，何者詞語使用最恰當？", "options": ["他的書法遒勁，力透紙背，真不愧為當代名家", "強震過後餘震不斷，許多人宵衣旰食不敢入睡", "飲食宜節制，不可吃軟不吃硬，以免消化不良", "百貨公司週年慶總是萬頭攢動，令人捉襟見肘"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 10, "raw_text": "10. 下列文句，何者詞語使用最恰當？\n    (A)他的書法遒勁，力透紙背，真不愧為當代名家\n    (B)強震過後餘震不斷，許多人宵衣旰食不敢入睡\n    (C)飲食宜節制，不可吃軟不吃硬，以免消化不良\n    (D)百貨公司週年慶總是萬頭攢動，令人捉襟見肘\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-011", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "「文化其實體現在一個人如何對待這世間的態度。在一個文化厚實深沉的社會裡，\n人懂得尊重□□ ―― 他不苟且，因為不苟且所以有品味；人懂得尊重□□ ――\n他不霸道，因為不霸道所以有道德；人懂得尊重□□ ―― 他不掠奪，因為不掠奪\n所以有永續的智慧。」根據這段文字的內容，空格處依序應填入下列何者最恰當？", "options": ["自己／別人／自然", "別人／自己／自然", "自己／自然／別人", "別人／自然／自己"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 11, "raw_text": "11. 「文化其實體現在一個人如何對待這世間的態度。在一個文化厚實深沉的社會裡，\n     人懂得尊重□□ ―― 他不苟且，因為不苟且所以有品味；人懂得尊重□□ ――\n     他不霸道，因為不霸道所以有道德；人懂得尊重□□ ―― 他不掠奪，因為不掠奪\n     所以有永續的智慧。」根據這段文字的內容，空格處依序應填入下列何者最恰當？\n     (A)自己／別人／自然       (B)別人／自己／自然\n     (C)自己／自然／別人       (D)別人／自然／自己\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-012", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "「巴提族人群居在巴基斯坦北部最險惡的高山河谷，六百年前來自西藏。原先信\n奉的佛教在途中漸被拭去，取而代之的是嚴峻的伊斯蘭教 什葉派，但仍保有原\n有的語言。他們體型瘦小、耐力驚人，具有生存在鮮有人造訪的高海拔地區的\n卓越能力，這些都不免讓人聯想起巴提族在東邊的遠親――尼泊爾的雪巴族。\n不過巴提人的其他特質，例如對外人的沉默懷疑以及毫不妥協的宗教信仰，則\n迥異於信奉佛教的雪巴人。」根據這段文句，下列何者最可能是巴提族和雪巴族\n都具有的特色？", "options": ["信奉嚴峻的伊斯蘭教 什葉派", "住在巴基斯坦北部高山地區", "對外人沉默懷疑、毫不妥協", "體型瘦小，且有驚人的耐力"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 12, "raw_text": "12. 「巴提族人群居在巴基斯坦北部最險惡的高山河谷，六百年前來自西藏。原先信\n    奉的佛教在途中漸被拭去，取而代之的是嚴峻的伊斯蘭教 什葉派，但仍保有原\n    有的語言。他們體型瘦小、耐力驚人，具有生存在鮮有人造訪的高海拔地區的\n    卓越能力，這些都不免讓人聯想起巴提族在東邊的遠親――尼泊爾的雪巴族。\n    不過巴提人的其他特質，例如對外人的沉默懷疑以及毫不妥協的宗教信仰，則\n    迥異於信奉佛教的雪巴人。」根據這段文句，下列何者最可能是巴提族和雪巴族\n    都具有的特色？\n    (A)信奉嚴峻的伊斯蘭教 什葉派\n    (B)住在巴基斯坦北部高山地區\n    (C)對外人沉默懷疑、毫不妥協\n    (D)體型瘦小，且有驚人的耐力\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-013", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "下列文句，何者用字完全正確？", "options": ["未來充滿變數，生活總是戰戰競競", "能受到民眾愛載，全因為他的魅力", "事情發展如此詭譎，讓人忐忑不安", "聽到這個噩號，令我不知如何是好"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 13, "raw_text": "13. 下列文句，何者用字完全正確？\n    (A)未來充滿變數，生活總是戰戰競競 (B)能受到民眾愛載，全因為他的魅力\n    (C)事情發展如此詭譎，讓人忐忑不安 (D)聽到這個噩號，令我不知如何是好\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-108-chinese-014", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-108-chinese", "question_type": "single_choice", "question_text": "有位作家曾說：「現代的年輕人都不會寫作，他們寫的小說千篇一律都是『兩\n個面貌模糊的人，在一個空曠的地方對話』。」根據這段文字，現代年輕人寫\n小說的缺點，不包含下列何者？", "options": ["寫作手法過於單調", "均以第一人稱的觀點表述", "小說人物缺乏性格及特色", "欠缺場景的描繪與氣氛的營造"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3524d2dcb418", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": 1.0, "original_question_number": 14, "raw_text": "14. 有位作家曾說：「現代的年輕人都不會寫作，他們寫的小說千篇一律都是『兩\n    個面貌模糊的人，在一個空曠的地方對話』。」根據這段文字，現代年輕人寫\n    小說的缺點，不包含下列何者？\n    (A)寫作手法過於單調\n    (B)均以第一人稱的觀點表述\n    (C)小說人物缺乏性格及特色\n    (D)欠缺場景的描繪與氣氛的營造\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
